def convert(s: str, numRows: int) -> str:
    if numRows == 1:
        return s

    rows = [[] for _ in range(numRows)]
    current_row = 0
    going_down = True

    for char in s:
        rows[current_row].append(char)

        if going_down:
            current_row += 1
        else:
            current_row -= 1

        if current_row == 0:
            going_down = True
        elif current_row == numRows - 1:
            going_down = False

    result = []
    for row in rows:
        result.append("".join(row))

    return "".join(result)
